def search_with_metadata_filtering(
    index_path: str,
    query: str,
    metadata_filters: Dict[str, Dict[str, Any]],
    top_k: int = 5
) -> List[SearchResult]:
    """Search in an index and apply metadata filters to results.

    Args:
        index_path: Path to the LEANN index file
        query: Search query string
        metadata_filters: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        top_k: Number of results to retrieve (default: 5)

    Returns:
        List of SearchResult objects that match both the query and metadata filters

    Raises:
        FileNotFoundError: If index file is not found
    """
    # Check if index file exists
    index_file = Path(index_path)
    if not index_file.exists():
        raise FileNotFoundError(f"Index file not found: {index_path}")

    # Create searcher instance
    searcher = LeannSearcher(index_path)

    # Perform search
    results = searcher.search(query, top_k=top_k)

    # Apply metadata filters
    filtered_results = []
    for result in results:
        if _matches_filters(result, metadata_filters):
            filtered_results.append(result)

    return filtered_results


def _matches_filters(result: SearchResult, filters: Dict[str, Dict[str, Any]]) -> bool:
    """Check if a search result matches all metadata filters.

    Args:
        result: SearchResult object to check
        filters: Dictionary of filter specifications

    Returns:
        True if result matches all filters, False otherwise
    """
    for field_name, filter_spec in filters.items():
        for operator, value in filter_spec.items():
            # Get the field value from result metadata
            if not hasattr(result, 'metadata') or field_name not in result.metadata:
                return False

            field_value = result.metadata[field_name]

            # Apply operator
            if operator == "==":
                if field_value != value:
                    return False
            elif operator == "!=":
                if field_value == value:
                    return False
            elif operator == ">":
                if field_value <= value:
                    return False
            elif operator == ">=":
                if field_value < value:
                    return False
            elif operator == "<":
                if field_value >= value:
                    return False
            elif operator == "<=":
                if field_value > value:
                    return False
            else:
                # Unknown operator
                return False

    return True
